func filterDealRows(rows []DealRow, minDiscount int, maxPrice float64, limit int) []DealRow {
	filtered := make([]DealRow, 0, len(rows))
	for _, row := range rows {
		if minDiscount > 0 && row.PercentOff < minDiscount {
			continue
		}
		if maxPrice > 0 && row.SalePrice > maxPrice {
			continue
		}
		filtered = append(filtered, row)
		if limit > 0 && len(filtered) >= limit {
			break
		}
	}
	return filtered
}

